import { useState, useEffect } from 'react';
import { motion } from 'motion/react';
import { supabase } from '../lib/supabase';

export default function About() {
  const [content, setContent] = useState<any>({
    subtitle: 'About the Studio',
    title: 'Creating joyful, layered spaces that reflect the people who live in them.',
    p1: 'We approach each project with a fresh perspective, combining classical principles with unexpected details. Our studio believes that a well-designed space should not only look beautiful but completely function around your lifestyle.',
    p2: 'From historic renovations to modern new builds, our work is defined by bespoke craftsmanship, rich textures, and a profound respect for architectural integrity.',
    image: 'https://images.unsplash.com/photo-1599839619722-39751411ea63?auto=format&fit=crop&q=80&w=800',
    est_year: '2016'
  });

  useEffect(() => {
    const fetchContent = async () => {
      const { data, error } = await supabase
        .from('content')
        .select('*')
        .eq('id', 'about')
        .single();

      if (data) {
        setContent((prev: any) => ({ 
          ...prev, 
          ...data, 
          subtitle: data.subtitle ?? prev.subtitle,
          title: data.title ?? prev.title,
          p1: data.p1 ?? prev.p1,
          p2: data.p2 ?? prev.p2,
          image: data.image ?? prev.image,
          est_year: data.est_year ?? prev.est_year
        }));
      }
    };

    fetchContent();

    const channel = supabase.channel('about_changes')
      .on('postgres_changes', { event: '*', schema: 'public', table: 'content', filter: 'id=eq.about' }, (payload) => {
        if (payload.new) {
          const d = payload.new as any;
          setContent((prev: any) => ({ 
            ...prev, 
            ...d, 
            subtitle: d.subtitle ?? prev.subtitle,
            title: d.title ?? prev.title,
            p1: d.p1 ?? prev.p1,
            p2: d.p2 ?? prev.p2,
            image: d.image ?? prev.image,
            est_year: d.est_year ?? prev.est_year
          }));
        }
      })
      .subscribe();

    return () => {
      supabase.removeChannel(channel);
    };
  }, []);

  return (
    <section id="about" className="py-24 md:py-40 px-6 lg:px-12 bg-alabaster">
      <div className="container mx-auto">
        <div className="grid lg:grid-cols-12 gap-12 items-center">

          <div className="lg:col-span-5 relative">
            <motion.div
              initial={{ opacity: 0, y: 30 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ duration: 1 }}
              className="bg-pale-white p-4 pb-16 md:p-6 md:pb-20 shadow-xl shadow-black/5 rotate-[-2deg] relative z-10"
            >
              <img 
                src={content.image} 
                alt="Studio image"
                className="w-full h-auto aspect-square object-cover grayscale opacity-90"
              />
              {content.est_year && (
                <p className="absolute bottom-6 md:bottom-8 left-1/2 -translate-x-1/2 font-sans text-xs tracking-widest text-black/60 uppercase">
                  Est. {content.est_year}
                </p>
              )}
            </motion.div>
          </div>

          <div className="lg:col-span-6 lg:col-start-7">
            <h2 className="font-sans text-sm tracking-widest uppercase text-dark-khaki mb-6">{content.subtitle}</h2>
            <h3 className="font-serif text-3xl md:text-5xl lg:text-6xl text-black leading-tight mb-8 whitespace-pre-wrap">
              {content.title}
            </h3>

            <p className="font-sans text-stone-600 leading-relaxed mb-8 whitespace-pre-wrap">
              {content.p1}
            </p>

            <p className="font-sans text-stone-600 leading-relaxed mb-12 whitespace-pre-wrap">
              {content.p2}
            </p>
          </div>

        </div>
      </div>
    </section>
  );
}

import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'motion/react';
import { X, Calendar, Loader2, ArrowRight } from 'lucide-react';
import { supabase } from '../lib/supabase';
import { User } from '@supabase/supabase-js';

type ViewState = 'loading' | 'auth_choice' | 'login' | 'signup' | 'book' | 'success';

interface AppointmentModalProps {
  isOpen: boolean;
  onClose: () => void;
}

export default function AppointmentModal({ isOpen, onClose }: AppointmentModalProps) {
  const [view, setView] = useState<ViewState>('loading');
  const [user, setUser] = useState<User | null>(null);
  const [isLoading, setIsLoading] = useState(false);
  const [error, setError] = useState('');

  // Form states
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  // Booking states
  const [date, setDate] = useState('');
  const [service, setService] = useState('Consultation');

  useEffect(() => {
    supabase.auth.getSession().then(({ data: { session } }) => {
      const currentUser = session?.user || null;
      setUser(currentUser);
      if (isOpen) {
        if (currentUser) setView('book');
        else setView('auth_choice');
      }
    });

    const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
      const currentUser = session?.user || null;
      setUser(currentUser);
      if (isOpen) {
        if (currentUser) setView('book');
        else setView('auth_choice');
      }
    });

    return () => subscription.unsubscribe();
  }, [isOpen]);

  // Reset states when closed
  useEffect(() => {
    if (!isOpen) {
      setTimeout(() => {
        setError('');
        setIsLoading(false);
        if (user) setView('book');
        else setView('auth_choice');
      }, 500);
    }
  }, [isOpen, user]);

  const handleSignup = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    try {
      const { error: signUpError } = await supabase.auth.signUp({
        email,
        password,
        options: { data: { full_name: name } }
      });

      if (!signUpError) {
        // Signup succeeded — try to sign in immediately (works when email confirm is OFF)
        const { error: signInError } = await supabase.auth.signInWithPassword({ email, password });
        if (signInError) {
          setError('Account created! Please check your email to confirm, then sign in.');
        }
        // If signInError is null, auth state change listener will move to book view automatically
      } else {
        // Check if the error is email rate limit — if so, user might already exist, try signing in
        const msg = signUpError.message?.toLowerCase() || '';
        if (msg.includes('rate limit') || msg.includes('email rate') || msg.includes('too many')) {
          // Try direct sign-in — user may already have an account
          const { error: signInError } = await supabase.auth.signInWithPassword({ email, password });
          if (!signInError) {
            // Successfully signed in — all good
            return;
          } else {
            setError('Too many signup attempts. Please wait a few minutes and try again, or sign in if you already have an account.');
          }
        } else if (msg.includes('already registered') || msg.includes('user already exists')) {
          // User already exists — try signing in
          const { error: signInError } = await supabase.auth.signInWithPassword({ email, password });
          if (!signInError) return;
          setError('This email is already registered. Please sign in instead.');
        } else {
          throw signUpError;
        }
      }
    } catch (err: any) {
      setError(err.message || 'Failed to create account.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogin = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    setIsLoading(true);
    setError('');
    try {
      const { error: signInError } = await supabase.auth.signInWithPassword({ email, password });
      if (signInError) throw signInError;
    } catch (err: any) {
      setError(err.message || 'Invalid email or password.');
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setView('auth_choice');
  };

  const handleBook = async (e: React.FormEvent<HTMLFormElement>) => {
    e.preventDefault();
    if (!user) return;

    setIsLoading(true);
    setError('');

    try {
      const { error: insertError } = await supabase.from('bookings').insert([{
        userid: user.id,
        useremail: user.email,
        username: name || user.user_metadata?.full_name || user.email?.split('@')[0] || 'Unknown',
        date,
        service,
        status: 'pending',
        createdat: new Date().toISOString()
      }]);
      if (insertError) throw insertError;
      setView('success');
    } catch (err: any) {
      setError('Could not complete booking. Please try again or contact us directly.');
      console.error(err);
    } finally {
      setIsLoading(false);
    }
  };

  const renderContent = () => {
    switch (view) {
      case 'loading':
        return (
          <div className="flex flex-col items-center justify-center h-64">
            <Loader2 className="w-8 h-8 animate-spin text-dark-khaki" />
          </div>
        );

      case 'auth_choice':
        return (
          <motion.div 
            initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}
            className="flex flex-col space-y-6 text-center"
          >
            <h2 className="font-serif text-3xl text-black">Welcome to Studio</h2>
            <p className="font-sans text-stone-600 text-sm">Please sign in or create an account to book your consultation.</p>

            <div className="flex flex-col space-y-4 mt-6">
              <button 
                onClick={() => setView('login')}
                className="w-full bg-black text-white font-sans uppercase tracking-widest text-xs py-4 hover:bg-dark-khaki transition-colors"
              >
                Sign In
              </button>
              <button 
                onClick={() => setView('signup')}
                className="w-full border border-black text-black font-sans uppercase tracking-widest text-xs py-4 hover:bg-black hover:text-white transition-colors"
              >
                Create Account
              </button>
            </div>
          </motion.div>
        );

      case 'login':
        return (
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -10 }}>
            <button onClick={() => setView('auth_choice')} className="text-xs text-stone-500 hover:text-black uppercase tracking-widest mb-6 block">&larr; Back</button>
            <h2 className="font-serif text-3xl text-black mb-6">Sign In</h2>
            {error && <p className="text-red-500 text-xs mb-4">{error}</p>}
            <form onSubmit={handleLogin} className="space-y-4">
              <div>
                <label className="block font-sans text-xs uppercase tracking-widest text-stone-500 mb-2">Email</label>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)}
                  className="w-full border-b border-stone-300 py-2 focus:outline-none focus:border-dark-khaki bg-transparent rounded-none" />
              </div>
              <div>
                <label className="block font-sans text-xs uppercase tracking-widest text-stone-500 mb-2">Password</label>
                <input type="password" required value={password} onChange={(e) => setPassword(e.target.value)}
                  className="w-full border-b border-stone-300 py-2 focus:outline-none focus:border-dark-khaki bg-transparent rounded-none" />
              </div>
              <button type="submit" disabled={isLoading} className="w-full bg-black text-white font-sans uppercase tracking-widest text-xs py-4 mt-4 hover:bg-dark-khaki transition-colors disabled:opacity-50 flex justify-center items-center">
                {isLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : 'Sign In'}
